INSERT INTO `t_post` VALUES (73, '码农刚子', 'imported-23787', 'ML.NET 快速入门与实践教程：开源机器学习框架 千淘万漉虽辛苦，吹尽狂沙始到金。嗨，大家好！我是码农刚子。今天和大家聊一聊ML.NET 如何快速入门。 ML.', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
INSERT INTO `t_post` VALUES (74, 'Java虚拟线程详解', 'java-23822', 'Java虚拟线程详解 引言 依稀还记得2016年开始学Java的场景，时光的距离是如此简短，十年时间仿佛隔桌而坐。刚学java时用的还是jdk1.6（jdk6），到现在最新的', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
INSERT INTO `t_post` VALUES (75, '程序员鱼皮', 'imported-23847', '离大谱，我竟然在 VS Code 里做了个视频！ 最近发现一个很有意思的开源项目，能用编程写代码的方式做视频动画，在 Gi', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
INSERT INTO `t_post` VALUES (76, '程序收割机', 'redis-visualization-client-comparison', '本文对比了多款Redis可视化客户端工具，包括yunedit-redis、RDM、AnotherRedisDesktopManager、medis、RedisInsight和Tiny RDM，从功能、语言支持、用户体验及适用场景等方面进行分析，并推荐更适合中国用户的yunedit-redis。', '', 4, 75, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, 'Redis可视化客户端工具推荐与对比', '对比主流Redis可视化工具，推荐适合中国用户的功能全面客户端yunedit-redis。', 'Redis, 可视化工具, 客户端推荐, yunedit-redis, RedisInsight', NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
INSERT INTO `t_post` VALUES (77, 'zhally', 'zhally-23905', 'Maui 实践：Go 接口以类型之名，给 runtime 传递方法参数 Maui 实践：Go 接口以类型之名，给 runtime 传递方法参数 原创 夏群林 202', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
