INSERT INTO `t_post` VALUES (81, 'aixueforever', 'aixueforever-24026', '非统一内存访问架构NUMA 什么是NUMA架构 简单来说，NUMA（Non-Uniform Memory Access，非统一内存访问架构） 是一种为了提高多处理器', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:00:24', '2026-03-02 17:00:24');
INSERT INTO `t_post` VALUES (82, 'Java虚拟线程详解', 'java-17743', '引言 依稀还记得2016年开始学Java的场景，时光的距离是如此简短，十年时间仿佛隔桌而坐。刚学java时用的还是jdk1.6（jdk6），到现在最新的jdk版本已经是29了，在java圈子里有一个诙谐的说法来形容jdk的快速迭代，“新版任你发，我用java8，你升随你升，我用java8”，这既是玩笑，也是真实写照。就我个人而言，使用的最多的也是jdk8，在22年后新项目都升级到了jdk17，今', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (83, '程序员鱼皮', 'imported-17763', '大家好，我是程序员鱼皮。 最近发现一个很有意思的开源项目叫 Remotion，能用编程写代码的方式做视频动画，在 GitHub 上星星很多。 你可能会问：用代码做视频？那不得累死？ 别急，我们当然不会自己写代码。让 AI 帮你写就完了！ 用 AI 编程做动画的原理其实很简单： AI 写代码 Remotion 把代码渲染成视频 下面我带大家完整走一遍流程，从安装到出片，全程手把手，保姆皮上', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (84, '程序收割机', 'imported-17783', 'redis可视化客户端可谓五花八门，用过之后，发现有些并不好用，下面对市场上最常用的几款redis客户端工具进行点评。 （1）yunedit-redis：针对中国人开发的可视化客户端工具，界面很炫，用户体验非常好。除了基本的增删查改外，其数据迁移和数据备份能力也是这些工具中最出色的，还具有ssh隧道功能，在服务器没开放redis对外端口的场景下，也可以通过ssh隧道，安全连接内网的redis服务', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (85, 'zhally', 'zhally-17807', 'Maui 实践：Go 接口以类型之名，给 runtime 传递方法参数 原创 夏群林 2026.3.2 Go 语言的接口，很奇妙。本人是从 C# 转过来的，很喜欢 Go 的接口方式。作为强类型语言，Go 在静态编译与动态调度之间，做了精妙取舍，也是对类型这一核心概念的深刻践行。 一、静态语言与动态语言的核心区别，从来不是是否有类型 一个常见的认知误区：静态语言有类型，动态语言没有类型。 事实上，', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (86, 'xiaoniu142857\'s Blog', 'xiaoniu142857-s-blog-17834', '第一次 div.2 场切 3 道！ 题目大意 给定一棵树，每个点上有一个对换 \\(\\sigma_i=(a_i b_i)\\)。\\(q\\) 次询问，每次给定 \\(u,v,x\\)。设 \\(u\\to v\\) 路径上的点分别是 \\(u,k_1,k_2,\\dots,k_m,v\\)，求 \\(\\sigma_v\\sigma_{k_m}\\dots\\sigma_{k_1}\\sigma_u(x)\\)，即对路径上对换复合', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (87, '鸿蒙应用开发UI基础第十五节：文本输入组件核心讲解与实战', 'ui-17854', '【学习目标】 区分TextInput、TextArea、Search三大组件的核心差异，掌握精准的场景选型逻辑； 掌握三大组件的基础创建、输入类型配置、样式定制，适配各类输入开发场景； 熟练绑定核心通用事件，实现输入数据的获取与业务处理； 掌握Search专属能力与三大组件控制器的精细控制用法； 掌握输入内容过滤的核心实现方式，保证输入内容合法性； 具备输入校验、键盘避让等实战能力，独立完成登', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (88, '公司给团队配了Cursor，然后开始裁员：一个残酷但必须面对的真相', 'cursor-17889', '昨天晚上，一个做了5年Java的朋友给我发微信： \"公司刚给我们配了Cursor和ChatGPT Plus，说要提升开发效率。今天早上，HR找我谈话，说团队要优化20%的人。\" 他问我：\"是不是AI真的要替代程序员了？\" 我沉默了很久。 这不是个例。 最近听到太多类似的消息： 某互联网大厂，研发团队从50人优化到35人 某外包公司，初级开发岗位招聘冻结 某创业公司，2个高级工程师 + AI', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (89, 'aixueforever', 'aixueforever-17915', '什么是NUMA架构 简单来说，NUMA（Non-Uniform Memory Access，非统一内存访问架构） 是一种为了提高多处理器系统（多核 CPU）处理效率的内存设计方案。 在传统的架构中，所有处理器访问内存的速度是一样的；而在 NUMA 架构下，处理器访问“离自己近”的内存比访问“远程”内存要快得多。 1. 为什么会出现 NUMA？ 在早期的 UMA（Uniform Memory A', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (90, 'AI-Frontiers 公#众#号：AI-Frontiers', 'ai-frontiers-ai-frontiers-17944', '原文: https://mp.weixin.qq.com/s/5viL2gJE3IfmVS1WxTlZAQ 关注gzh: AI-Frontiers 往期文章推荐 小白也能看懂的RL-PPO 收藏！强化学习从入门到封神：5 本经典教材 + 8 大实战项目 + 7个免费视频，一站式搞定 小白也能看懂的RLHF：基础篇 小白也能看懂的RLHF-PPO：原理篇 小白也能看懂的LLM-RL算法：PPO/D', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
INSERT INTO `t_post` VALUES (91, 'MyBatis-mybatis入门与增删改查', 'mybatis-mybatis-18042', '了解Mybatis Mybatis是一个持久层框架，半自动化ORM（Hibernate属于全自动化ORM）。 Mybatis的特点： 支持定制化sql、存储过程、基本映射以及高级映射 避免了几乎所有的JDBC代码中手动设置参数以及获取结果集 支持XML开发，也支持注解式开发 将接口和Java的pojo映射成数据库中的记录 体积小，易上手 完全做到sql解耦 提供了基本映射标签和高级映射标签 提', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 17:11:58', '2026-03-02 17:11:58');
