INSERT INTO `t_post` VALUES (98, 'AI-Frontiers 公#众#号：AI-Frontiers', 'ai-frontiers-ai-frontiers-71947', '原文: https://mp.weixin.qq.com/s/5viL2gJE3IfmVS1WxTlZAQ 关注gzh: AI-Frontiers 往期文章推荐 小白也能看懂的RL-PPO 收藏！强化学习从入门到封神：5 本经典教材 + 8 大实战项目 + 7个免费视频，一站式搞定 小白也能看懂的RLHF：基础篇 小白也能看懂的RLHF-PPO：原理篇 小白也能看懂的LLM-RL算法：PPO/D', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:01:12', '2026-03-02 18:01:12');
INSERT INTO `t_post` VALUES (99, 'MyBatis-mybatis入门与增删改查', 'mybatis-mybatis-71969', '了解Mybatis Mybatis是一个持久层框架，半自动化ORM（Hibernate属于全自动化ORM）。 Mybatis的特点： 支持定制化sql、存储过程、基本映射以及高级映射 避免了几乎所有的JDBC代码中手动设置参数以及获取结果集 支持XML开发，也支持注解式开发 将接口和Java的pojo映射成数据库中的记录 体积小，易上手 完全做到sql解耦 提供了基本映射标签和高级映射标签 提', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:01:12', '2026-03-02 18:01:12');
INSERT INTO `t_post` VALUES (100, 'FastAPI压力测试实战：Locust模拟真实用户并发及优化建议', 'fastapilocust-72013', '嘿，朋友们👋 你有没有遇到过这种情况：接口本地跑得飞快，一上线就被用户吐槽“卡成PPT”？或者更惨，直接502宕机，半夜被报警电话炸醒？ 上个月我就差点翻车——给一个活动写的FastAPI接口，预估峰值也就几百QPS，结果流量冲上来时数据库连接数直接爆了，整个服务瘫了半小时。事后复盘才发现：不是代码写得不好，而是根本没做压力测试！ 今天咱们就坐下来聊聊，怎么给FastAPI做压测，以及扛住高并', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:01:12', '2026-03-02 18:01:12');
INSERT INTO `t_post` VALUES (101, 'suiyuan129', 'suiyuan129-72043', 'kmp算法:我们所忽略的字符串匹配本质 众所周知，kmp算法是一个精妙且广为人知的算法，但我们似乎仅仅只是硬记或只是知晓它通过next数组与前后缀去完成匹配，根本没有看到它所精妙的地方。 不久前，我在刷视频时偶然看见了介绍kmp算法的视频，就开始推演我很久之前所学的kmp算法，推演着推演着我发现了我之前所未发现的字符串的匹配本质，以下我开始讲解。 字符串匹配，有一个资源串与目标串，我们先统一术语', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:01:12', '2026-03-02 18:01:12');
INSERT INTO `t_post` VALUES (102, '程序收割机', 'imported-47682', 'redis可视化客户端可谓五花八门，用过之后，发现有些并不好用，下面对市场上最常用的几款redis客户端工具进行点评。 （1）yunedit-redis：针对中国人开发的可视化客户端工具，界面很炫，用户体验非常好。除了基本的增删查改外，其数据迁移和数据备份能力也是这些工具中最出色的，还具有ssh隧道功能，在服务器没开放redis对外端口的场景下，也可以通过ssh隧道，安全连接内网的redis服务', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:02:28', '2026-03-02 18:02:28');
INSERT INTO `t_post` VALUES (103, 'zhally', 'zhally-47704', 'Maui 实践：Go 接口以类型之名，给 runtime 传递方法参数 原创 夏群林 2026.3.2 Go 语言的接口，很奇妙。本人是从 C# 转过来的，很喜欢 Go 的接口方式。作为强类型语言，Go 在静态编译与动态调度之间，做了精妙取舍，也是对类型这一核心概念的深刻践行。 一、静态语言与动态语言的核心区别，从来不是是否有类型 一个常见的认知误区：静态语言有类型，动态语言没有类型。 事实上，', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:02:28', '2026-03-02 18:02:28');
INSERT INTO `t_post` VALUES (104, 'xiaoniu142857\'s Blog', 'xiaoniu142857-s-blog-47725', '第一次 div.2 场切 3 道！ 题目大意 给定一棵树，每个点上有一个对换 \\(\\sigma_i=(a_i b_i)\\)。\\(q\\) 次询问，每次给定 \\(u,v,x\\)。设 \\(u\\to v\\) 路径上的点分别是 \\(u,k_1,k_2,\\dots,k_m,v\\)，求 \\(\\sigma_v\\sigma_{k_m}\\dots\\sigma_{k_1}\\sigma_u(x)\\)，即对路径上对换复合', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:02:28', '2026-03-02 18:02:28');
INSERT INTO `t_post` VALUES (105, '鸿蒙应用开发UI基础第十五节：文本输入组件核心讲解与实战', 'ui-47743', '【学习目标】 区分TextInput、TextArea、Search三大组件的核心差异，掌握精准的场景选型逻辑； 掌握三大组件的基础创建、输入类型配置、样式定制，适配各类输入开发场景； 熟练绑定核心通用事件，实现输入数据的获取与业务处理； 掌握Search专属能力与三大组件控制器的精细控制用法； 掌握输入内容过滤的核心实现方式，保证输入内容合法性； 具备输入校验、键盘避让等实战能力，独立完成登', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:02:28', '2026-03-02 18:02:28');
