INSERT INTO `t_post` VALUES (119, 'MyBatis-mybatis入门与增删改查', 'mybatis-mybatis-39206', '# 了解Mybatis Mybatis是一个持久层框架，半自动化ORM（Hibernate属于全自动化ORM）。 Mybatis的特点： - 支持定制化sql、存储过程、基本映射以及高级映射 - 避免了几乎所有的JDBC代码中手动设置参数以及获取结果集 - 支持XML开发，也支持注解式开发 - 将接口和Java的pojo映射成数据库中的记录 - 体积小，易上手 - 完全做到sql解', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:25:39', '2026-03-02 18:25:39');
