INSERT INTO `t_post` VALUES (121, 'suiyuan129', 'suiyuan129-39251', '# kmp算法:我们所忽略的字符串匹配本质 众所周知，kmp算法是一个精妙且广为人知的算法，但我们似乎仅仅只是硬记或只是知晓它通过next数组与前后缀去完成匹配，根本没有看到它所精妙的地方。 不久前，我在刷视频时偶然看见了介绍kmp算法的视频，就开始推演我很久之前所学的kmp算法，推演着推演着我发现了我之前所未发现的字符串的匹配本质，以下我开始讲解。 字符串匹配，有一个资源串与目标串，我们先', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:25:39', '2026-03-02 18:25:39');
INSERT INTO `t_post` VALUES (122, 'zhally', 'zhally-58691', '# Maui 实践：Go 接口以类型之名，给 runtime 传递方法参数 原创 夏群林 2026.3.2 Go 语言的接口，很奇妙。本人是从 C# 转过来的，很喜欢 Go 的接口方式。作为强类型语言，Go 在静态编译与动态调度之间，做了精妙取舍，也是对类型这一核心概念的深刻践行。 # 一、静态语言与动态语言的核心区别，从来不是是否有类型 一个常见的认知误区：静态语言有类型，动态语言没有类', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:29:19', '2026-03-02 18:29:19');
INSERT INTO `t_post` VALUES (123, 'xiaoniu142857\'s Blog', 'xiaoniu142857-s-blog-58712', '第一次 div.2 场切 3 道！ ## 题目大意 给定一棵树，每个点上有一个对换 \\(\\sigma_i=(a_i b_i)\\)。\\(q\\) 次询问，每次给定 \\(u,v,x\\)。设 \\(u\\to v\\) 路径上的点分别是 \\(u,k_1,k_2,\\dots,k_m,v\\)，求 \\(\\sigma_v\\sigma_{k_m}\\dots\\sigma_{k_1}\\sigma_u(x)\\)，即对路径上', 'http://localhost:3000/storage/2026/03/c8d8435631cf48e194190b8bd2d3762e.webp', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:29:19', '2026-03-02 18:29:19');
INSERT INTO `t_post` VALUES (124, '鸿蒙应用开发UI基础第十五节：文本输入组件核心讲解与实战', 'ui-58730', '## 【学习目标】 - 区分TextInput、TextArea、Search三大组件的核心差异，掌握精准的场景选型逻辑； - 掌握三大组件的基础创建、输入类型配置、样式定制，适配各类输入开发场景； - 熟练绑定核心通用事件，实现输入数据的获取与业务处理； - 掌握Search专属能力与三大组件控制器的精细控制用法； - 掌握输入内容过滤的核心实现方式，保证输入内容合法性； - 具备输', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:29:19', '2026-03-02 18:29:19');
INSERT INTO `t_post` VALUES (125, '公司给团队配了Cursor，然后开始裁员：一个残酷但必须面对的真相', 'cursor-58754', '昨天晚上，一个做了5年Java的朋友给我发微信： \"公司刚给我们配了Cursor和ChatGPT Plus，说要提升开发效率。今天早上，HR找我谈话，说团队要优化20%的人。\" 他问我：\"是不是AI真的要替代程序员了？\" 我沉默了很久。 这不是个例。 最近听到太多类似的消息： - 某互联网大厂，研发团队从50人优化到35人 - 某外包公司，初级开发岗位招聘冻结 - 某创业公司，2个', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:29:19', '2026-03-02 18:29:19');
INSERT INTO `t_post` VALUES (126, 'aixueforever', 'aixueforever-58776', '# 什么是NUMA架构 简单来说，**NUMA（Non-Uniform Memory Access，非统一内存访问架构）** 是一种为了提高多处理器系统（多核 CPU）处理效率的内存设计方案。 在传统的架构中，所有处理器访问内存的速度是一样的；而在 NUMA 架构下，处理器访问“离自己近”的内存比访问“远程”内存要快得多。 ### 1. 为什么会出现 NUMA？ 在早期的 **UMA（Un', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:29:19', '2026-03-02 18:29:19');
