INSERT INTO `t_post` VALUES (140, '深入剖析 nanobot：轻量级 AI Agent 框架的架构之道', 'nanobot-ai-agent-13580', '**摘要**：nanobot 是一个极简主义的 AI Agent 框架，它用不到 4000 行代码，构建了一个包含 **多端接入 (Channel)**、**消息总线 (Bus)**、**ReAct 循环**、**多层记忆 (Memory)** 以及 **技能扩展 (Skills)** 的完整系统。本文将从源码视角，剖析其核心设计理念，帮助开发者理解现代 AI Agent 的底层运作机制。 ##', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, '2026-03-02 18:36:54', '2026-03-02 18:36:54');
INSERT INTO `t_post` VALUES (141, '【Python 教程】如何将 JSON 数据转换为 Excel 工作表', 'python-json-excel-96673', '在数据处理场景中，JSON 作为轻量级数据交换格式被广泛使用，而 Excel 则是业务分析、数据交付的核心载体。将 JSON 数据结构化转换为 Excel 文件，是日常开发中高频且基础的需求。本文将介绍如何使用免费库 Free Spire.XLS for Python 完成这一转换任务，并提供处理复杂嵌套数据的实用方案。 ## 一、环境准备 ### 1.1 安装依赖 在开始编码之前，需要安装', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 1, '2026-03-05 19:34:57', '2026-03-05 19:46:01');
INSERT INTO `t_post` VALUES (142, 'lily-is-here', 'lily-is-here-18463', '## 结构级优化 ### 设计结构的选择 在DW中选择最合适的结构或算法实现电路功能 ### 数据通路的优化 - 选择CSA等算法优化数据通路设计 - 共享共同的子表达式（算术电路） - 减少比较器数目 ### 资源共享 算术运算资源共享的默认策略是约束驱动，可以使用DC的面积优化策略： ``` set hlo_resource_allocation area ``` `set', '', 74, NULL, 1, 'draft', 'immediate', NULL, 0, 0, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, 1, '2026-03-05 19:40:18', '2026-03-05 19:46:01');
INSERT INTO `t_post_content` VALUES (1, '# Vue3 组合式 API 完全指南\n\n## 前言\n\nVue3 的组合式 API 是一种全新的组织组件逻辑的方式。\n\n## setup 语法糖\n\n```vue\n<script setup lang=\"ts\">\nimport { ref, computed } from \"vue\"\n\nconst count = ref(0)\nconst doubled = computed(() => count.value * 2)\n</script>\n```\n\n## 响应式原理\n\nVue3 使用 Proxy 替代了 Vue2 的 Object.defineProperty。\n\n## 生命周期\n\n- `onMounted` - 组件挂载后\n- `onUpdated` - 组件更新后\n- `onUnmounted` - 组件卸载后', NULL, '2026-02-21 12:09:14');
INSERT INTO `t_post_content` VALUES (2, '# Pinia 状态管理最佳实践\n\n## 为什么选择 Pinia\n\nPinia 是 Vue 官方推荐的状态管理库，相比 Vuex 更简洁。\n\n## 定义 Store\n\n```ts\nexport const useUserStore = defineStore(\"user\", () => {\n  const name = ref(\"\")\n  const isLoggedIn = computed(() => !!name.value)\n  function login(username: string) {\n    name.value = username\n  }\n  return { name, isLoggedIn, login }\n})\n```', NULL, '2026-02-21 12:09:14');
